// ============================================================
// BUSCA DUAL PINECONE: devops-tickets (N2) + zendesk-tickets
// DevOps tem prioridade — causa raiz real
// ============================================================
const embedding = $('Vetorizar Pergunta V5').item.json.data[0].embedding;
const PINECONE_HOST = $env.PINECONE_INDEX_HOST;
const PINECONE_KEY  = $env.PINECONE_API_KEY;

async function queryNamespace(namespace, topK) {
  try {
    const res = await fetch(`${PINECONE_HOST}/query`, {
      method: 'POST',
      headers: { 'Api-Key': PINECONE_KEY, 'Content-Type': 'application/json' },
      body: JSON.stringify({ vector: embedding, topK, includeMetadata: true, namespace })
    });
    if (!res.ok) return [];
    const data = await res.json();
    return data.matches || [];
  } catch {
    return [];
  }
}

// Paralelo: DevOps topK=5, Zendesk topK=10
const [devopsMatches, zendeskMatches] = await Promise.all([
  queryNamespace('devops-tickets', 5),
  queryNamespace('zendesk-tickets', 10)
]);

return {
  devops_matches:  devopsMatches,
  zendesk_matches: zendeskMatches,
  devops_count:    devopsMatches.length,
  zendesk_count:   zendeskMatches.length,
  tem_devops:      devopsMatches.length > 0 && devopsMatches[0].score > 0.75
};

// ============================================================
// MONTAR PROMPT V5 — Diagnóstico + Causa Raiz + DevOps Priority
// ============================================================
const { question, ticket_id } = $('Validar Entrada V5').item.json;

// 1. Categoria
let categoria = 'OUTROS', confiancaCategoria = 0;
try {
  const content = $('Classificar Ticket V5').item.json.choices[0].message.content;
  const clean = content.replace(/```json?\s*/gi, '').replace(/```/g, '').trim();
  const parsed = JSON.parse(clean);
  categoria = parsed.categoria || 'OUTROS';
  confiancaCategoria = parsed.confianca || 0;
} catch {}

// 2. Memória Redis V5
let memoriaContexto = '';
try {
  const redisResult = $('Redis GET V5').item.json;
  if (redisResult.result) {
    const memoria = JSON.parse(redisResult.result);
    const historico = (memoria.historico || []).slice(-6);
    if (historico.length > 0) {
      memoriaContexto = historico.map((h, i) =>
        `[${i + 1}] Atendente: ${h.pergunta}\n    MarIA V5: ${h.resposta_resumo}\n    Diagnóstico: ${h.diagnostico || 'N/A'}`
      ).join('\n');
      const dados = memoria.dados_extraidos || {};
      if (Object.keys(dados).length > 0) {
        memoriaContexto += `\n\nDados coletados nesta sessão:\n${JSON.stringify(dados, null, 2)}`;
      }
    }
  }
} catch {}

// 3. Casos DevOps N2 (prioridade máxima)
const conhecimento = $('Buscar Conhecimento V5').item.json;
const devopsMatches = conhecimento.devops_matches || [];
const zendeskMatches = conhecimento.zendesk_matches || [];
const temDevopsForte = conhecimento.tem_devops;

let contextoDevOps = '';
if (devopsMatches.length > 0) {
  contextoDevOps = devopsMatches.map((m, i) => {
    const meta = m.metadata || {};
    const score = Math.round(m.score * 100);
    return [
      `[DevOps N2 — Item ${i + 1} | Similaridade: ${score}% | ID: ${meta.workitem_id || 'N/A'}]`,
      `Título: ${meta.titulo || 'N/A'}`,
      meta.problema   ? `Problema: ${meta.problema}`   : '',
      meta.causa_raiz ? `Causa Raiz: ${meta.causa_raiz}` : '',
      meta.analise    ? `Análise Técnica: ${meta.analise}` : '',
      meta.causa      ? `Causa: ${meta.causa}`         : '',
      meta.outcome    ? `Resolução: ${meta.outcome}`   : '',
      meta.cliente    ? `Cliente afetado: ${meta.cliente}` : '',
    ].filter(Boolean).join('\n');
  }).join('\n\n---\n\n');
} else {
  contextoDevOps = 'Nenhum caso N2 similar encontrado no DevOps.';
}

// 4. Casos Zendesk (padrões históricos)
let contextoZendesk = '';
if (zendeskMatches.length > 0) {
  contextoZendesk = zendeskMatches.map((m, i) => {
    const meta = m.metadata || {};
    const score = Math.round(m.score * 100);
    return [
      `[Zendesk ${i + 1} — Similaridade: ${score}% | Categoria: ${meta.categoria || 'N/A'}]`,
      `Problema: ${meta.problema || 'N/A'}`,
      meta.solucao ? `Solução: ${meta.solucao}` : '',
    ].filter(Boolean).join('\n');
  }).join('\n\n---\n\n');
} else {
  contextoZendesk = 'Nenhum ticket similar encontrado no Zendesk.';
}

const userPrompt = [
  `CATEGORIA: ${categoria} (confiança: ${confiancaCategoria}%)`,
  `TEM CASO DEVOPS FORTE (score>75%): ${temDevopsForte ? 'SIM — USE COMO VERDADE PRINCIPAL' : 'NÃO'}`,
  '',
  memoriaContexto
    ? `MEMÓRIA DA SESSÃO (ticket ${ticket_id}):\n${memoriaContexto}`
    : `MEMÓRIA: primeira interação neste ticket.`,
  '',
  `CASOS DEVOPS N2 (PRIORIDADE MÁXIMA — CAUSA RAIZ REAL):\n\n${contextoDevOps}`,
  '',
  `CASOS ZENDESK (PADRÕES HISTÓRICOS):\n\n${contextoZendesk}`,
  '',
  `PERGUNTA DO ATENDENTE:\n${question}`,
  '',
  'Responda seguindo a estrutura obrigatória do MarIA V5. Se houver caso DevOps forte, use a causa raiz do DevOps como principal.'
].join('\n');

return {
  userPrompt, question, ticket_id, categoria, confiancaCategoria,
  devops_count: devopsMatches.length, zendesk_count: zendeskMatches.length,
  tem_devops_forte: temDevopsForte, temMemoria: memoriaContexto.length > 0
};

const gptResponse = $input.item.json;
const promptData = $('Montar Prompt V5').item.json;
const resposta = gptResponse.choices[0].message.content;

// Extrai resumo da seção ✅ RESPOSTA DIRETA para memória
const matchDireto = resposta.match(/##\s*✅\s*RESPOSTA DIRETA\s*\n([\s\S]*?)(?:\n##|$)/);
const resumo = matchDireto ? matchDireto[1].trim().substring(0, 250) : resposta.substring(0, 250);

// Extrai diagnóstico para memória
const matchDiag = resposta.match(/##\s*🧠\s*DIAGNÓSTICO\s*\n([\s\S]*?)(?:\n##|$)/);
const diagnostico = matchDiag ? matchDiag[1].trim().substring(0, 150) : '';

return {
  sucesso: true,
  resposta,
  resumo_para_memoria: resumo,
  diagnostico_para_memoria: diagnostico,
  metadados: {
    pergunta_original: promptData.question,
    ticket_id: promptData.ticket_id,
    categoria: promptData.categoria,
    confianca_categoria: promptData.confiancaCategoria,
    devops_utilizados: promptData.devops_count,
    zendesk_utilizados: promptData.zendesk_count,
    tinha_devops_forte: promptData.tem_devops_forte,
    tinha_memoria: promptData.temMemoria,
    modelo: 'gpt-4o',
    versao: 'V5',
    tokens_usados: gptResponse.usage?.total_tokens || 0,
    timestamp: new Date().toISOString()
  }
};

const respostaData = $('Formatar Resposta V5').item.json;
const { ticket_id, pergunta_original, categoria } = {
  ticket_id: respostaData.metadados.ticket_id,
  pergunta_original: respostaData.metadados.pergunta_original,
  categoria: respostaData.metadados.categoria
};

let memoriaExistente = { historico: [], dados_extraidos: {} };
try {
  const redisResult = $('Redis GET V5').item.json;
  if (redisResult.result) memoriaExistente = JSON.parse(redisResult.result);
} catch {}

const novaInteracao = {
  pergunta: pergunta_original,
  resposta_resumo: respostaData.resumo_para_memoria,
  diagnostico: respostaData.diagnostico_para_memoria,
  categoria,
  timestamp: respostaData.metadados.timestamp
};

memoriaExistente.historico = [
  ...(memoriaExistente.historico || []),
  novaInteracao
].slice(-10);

const redisKey = `maria-v5:ticket:${ticket_id}`;
return {
  redis_key: redisKey,
  redis_value: JSON.stringify(memoriaExistente),
  ticket_id
};
